"use strict";parserFactory.register("dummynovels.com",()=>new DummynovelsParser);class DummynovelsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.chapter-arc-accordion p a")].map(e=>({sourceUrl:e.href,title:e.querySelector("label").innerText.trim()}))}findContent(e){return e.querySelector(".elementor-widget-theme-post-content")}extractTitleImpl(e){return e.querySelector(".elementor-heading-title")}findChapterTitle(e){return[...e.querySelectorAll(".chapter-heading")].pop()}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.site-content")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.novel-synopsis-content")]}cleanInformationNode(e){util.removeChildElementsMatchingSelector(e,"script, iframe, .code-block")}}